    index++;
  }
}

// 3. 从 Edit Fields 节点主动提取以 cpimage 开头的 binary 数据（使用 $('Edit Fields').all()）
let editFieldsImageCount = 0;
let editFieldsConnected = false;

try {
  const editFieldsOutput = $('Edit Fields').all();

  if (editFieldsOutput && editFieldsOutput.length > 0) {
    const firstItemFromEditFields = editFieldsOutput[0];
    if (firstItemFromEditFields && firstItemFromEditFields.binary) {
      const efBinary = firstItemFromEditFields.binary;
      console.log('Edit Fields binary keys:', Object.keys(efBinary));

      // 遍历 Edit Fields 的所有 binary 字段，查找以 'cpimage' 开头的
      for (const originalKey in efBinary) {
        if (Object.prototype.hasOwnProperty.call(efBinary, originalKey) && originalKey.startsWith('cpimage')) {
          const newKey = `${index + 1}图`;
          images[newKey] = { ...efBinary[originalKey] };

          // 添加来源标记，方便后续识别
          images[newKey].sourceNode = 'Edit Fields';
          images[newKey].sourceField = originalKey; // 记录原始字段名

          index++;
          editFieldsImageCount++;
        }
      }

      if (editFieldsImageCount > 0) {
        editFieldsConnected = true; // 标记为已成功连接并获取到数据
        console.log(`Successfully added ${editFieldsImageCount} image(s) from 'Edit Fields' node.`);
      } else {
        console.log("The 'Edit Fields' node does not contain any binary fields starting with 'cpimage'.");
      }
    } else {
      console.log("The 'Edit Fields' node output exists but contains no binary data.");
    }
  } else {
    console.log("The 'Edit Fields' node output is empty or not connected.");
  }
