// ================================================
// n8n Code 节点专用代码
// 功能1：从 AI Agent5 的 output 字段提取文字，并按【模块类型】分段整理
// 功能2：提取当前输入的所有 binary 图像（来自上游）
// 功能3：从 Edit Fields 节点提取以 cpimage 开头的 binary 并合并
// 返回：包含分段后的 descriptions + 合并后的 binary 图像
// ================================================

// 1. 提取并整理文本描述（从 AI Agent5 的 output 字段）
const raw = $input.first().json.output || '';

// 清理首尾标记
let text = raw
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

// 按 【模块类型】 分段（使用正则匹配每个模块块）
const modulePattern = /【模块类型】：(.+?)\n([\s\S]*?)(?=【模块类型】：|$)/g;
const descriptions = {};
let match;

while ((match = modulePattern.exec(text)) !== null) {
  let moduleType = match[1].trim();                    // 如 "主 Banner（顶部主图）"
  let moduleContent = match[2].trim();                 // 该模块的所有内容

  // 清理多余换行和空行
  moduleContent = moduleContent.replace(/\n{3,}/g, '\n\n').trim();

  if (moduleContent) {
    // 用模块类型作为 key（去掉【】，保持原样）
    descriptions[moduleType] = moduleContent;
  }
}

// 调试：看分了几个模块
console.log('Extracted module types:', Object.keys(descriptions));
console.log('Total modules:', Object.keys(descriptions).length);

// 2. 提取当前输入的所有 binary（来自直接上游节点）
const inputItems = $input.all();
const inputBinary = inputItems.length > 0 ? inputItems[0].binary || {} : {};
const images = {};
let index = 0;

// 打印当前输入的 binary 键名，用于调试
console.log('Binary keys in current item (from upstream):', Object.keys(inputBinary));

for (const originalKey in inputBinary) {
  if (Object.prototype.hasOwnProperty.call(inputBinary, originalKey)) {
    const newKey = `${index + 1}图`; // 重命名为 "1图"、"2图"...
    images[newKey] = { ...inputBinary[originalKey] };
    index++;
  }
}

// 3. 从 Edit Fields 节点主动提取以 cpimage 开头的 binary 数据
let editFieldsImageCount = 0;
let editFieldsConnected = false;

try {
  const editFieldsOutput = $('Edit Fields').all();

  if (editFieldsOutput && editFieldsOutput.length > 0) {
    const firstItemFromEditFields = editFieldsOutput[0];
    if (firstItemFromEditFields && firstItemFromEditFields.binary) {
      const efBinary = firstItemFromEditFields.binary;
      console.log('Edit Fields binary keys:', Object.keys(efBinary));

      for (const originalKey in efBinary) {
        if (Object.prototype.hasOwnProperty.call(efBinary, originalKey) && originalKey.startsWith('cpimage')) {
          const newKey = `${index + 1}图`;
          images[newKey] = { ...efBinary[originalKey] };
          images[newKey].sourceNode = 'Edit Fields';
          images[newKey].sourceField = originalKey;
          index++;
          editFieldsImageCount++;
        }
      }

      if (editFieldsImageCount > 0) {
        editFieldsConnected = true;
        console.log(`Successfully added ${editFieldsImageCount} image(s) from 'Edit Fields' node.`);
      } else {
        console.log("The 'Edit Fields' node does not contain any binary fields starting with 'cpimage'.");
      }
    } else {
      console.log("The 'Edit Fields' node output exists but contains no binary data.");
    }
  } else {
    console.log("The 'Edit Fields' node output is empty or not connected.");
  }
} catch (err) {
  console.error("Error retrieving data from 'Edit Fields' node:", err.message);
  editFieldsConnected = false;
}

// 4. 输出最终合并的结果
return [{
  json: {
    descriptions: descriptions,              // { "主 Banner（顶部主图）": "完整 Prompt + 标注...", ... }
    moduleCount: Object.keys(descriptions).length,
    imageCount: index,
    inputImageCount: Object.keys(inputBinary).length,
    editFieldsImageCount: editFieldsImageCount,
    editFieldsConnected: editFieldsConnected
  },
  binary: images                             // 合并后的 binary（"1图", "2图", ...）
}];
